using ArgParams = struct { unsigned int vecwidth; };

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__device__ __forceinline__ Element bench_block_device(Element* data) {
  Element sum = 0;

#ifdef BASELINE_IMPL
  Element f = data[0];
  #pragma unroll
  for (size_t i = 0; i < static_chunk_size; i++) {
    Element t = data[i];
    #pragma unroll
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }
#else
  Element f[] = {data[0], data[1], data[2], data[3],
                 data[4], data[5], data[6], data[7]};
  #pragma unroll
  for (size_t i = 0; i < static_chunk_size; i++) {
    Element t[] = {data[i], data[i], data[i], data[i],
                   data[i], data[i], data[i], data[i]};
    #pragma unroll
    for (size_t j = 0; j < compute_iterations / 8; j++) {
      t[0] = t[0] * t[0] + f[0];
      t[1] = t[1] * t[1] + f[1];
      t[2] = t[2] * t[2] + f[2];
      t[3] = t[3] * t[3] + f[3];
      t[4] = t[4] * t[4] + f[4];
      t[5] = t[5] * t[5] + f[5];
      t[6] = t[6] * t[6] + f[6];
      t[7] = t[7] * t[7] + f[7];
    }
    if constexpr (compute_iterations % 8 > 0) {
      t[0] = t[0] * t[0] + f[0];
    }
    if constexpr (compute_iterations % 8 > 1) {
      t[1] = t[1] * t[1] + f[1];
    }
    if constexpr (compute_iterations % 8 > 2) {
      t[2] = t[2] * t[2] + f[2];
    }
    if constexpr (compute_iterations % 8 > 3) {
      t[3] = t[3] * t[3] + f[3];
    }
    if constexpr (compute_iterations % 8 > 4) {
      t[4] = t[4] * t[4] + f[4];
    }
    if constexpr (compute_iterations % 8 > 5) {
      t[5] = t[5] * t[5] + f[5];
    }
    if constexpr (compute_iterations % 8 > 6) {
      t[6] = t[6] * t[6] + f[6];
    }
    sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
  }
#endif
  return sum;
}

template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_kernel(Element* src, size_t len, Element* result) {
  __shared__ Element sdata[256]; // assuming max 256 threads per block
  unsigned int tid = threadIdx.x;
  unsigned int idx = blockIdx.x * blockDim.x * static_chunk_size + threadIdx.x * static_chunk_size;

  Element sum = 0;
  if (idx + static_chunk_size <= len) {
    sum = bench_block_device<Element, compute_iterations, static_chunk_size>(&src[idx]);
  } else {
    // Handle tail elements if any
    for (size_t i = 0; i < static_chunk_size && (idx + i) < len; i++) {
      Element t = src[idx + i];
      #pragma unroll
      for (size_t j = 0; j < compute_iterations; j++) {
        t = t * t + src[0];
      }
      sum += t;
    }
  }
  sdata[tid] = sum;
  __syncthreads();

  // Reduction in shared memory
  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) {
      sdata[tid] += sdata[tid + s];
    }
    __syncthreads();
  }

  if (tid == 0) {
    atomicAdd(result, sdata[0]);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, Element* src, Element* d_result) {
  constexpr size_t static_chunk_size = 4096;
  const int threads_per_block = 256;
  int blocks = (int)((len + threads_per_block * static_chunk_size - 1) / (threads_per_block * static_chunk_size));

  cudaMemset(d_result, 0, sizeof(Element));
  bench_kernel<Element, compute_iterations, static_chunk_size><<<blocks, threads_per_block>>>(src, len, d_result);
  cudaDeviceSynchronize();

  Element h_result;
  cudaMemcpy(&h_result, d_result, sizeof(Element), cudaMemcpyDeviceToHost);
  *src = h_result;
  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto timer_start = std::chrono::steady_clock::now();

  double* ptr = new (c) double[num_elements];

  bench_cuda<double, 16>(num_elements, ptr, nullptr);

  auto timer_duration = std::chrono::steady_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration)
      .count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = std::chrono::steady_clock::now();
  op();
  auto timer_duration = std::chrono::steady_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration)
             .count() /
         1000.;
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  float *c_as_float = new (c) float[cs.element_count<float>()];
  float* d_c_as_float;
  cudaMalloc(&d_c_as_float, size);
  cudaMemcpy(d_c_as_float, c_as_float, size, cudaMemcpyHostToDevice);
  float kernel_time_mad_sp = measure_operation([&] {
    bench_cuda<float, compute_iterations>(cs.element_count<float>(), d_c_as_float, nullptr);
  });
  cudaMemcpy(c_as_float, d_c_as_float, size, cudaMemcpyDeviceToHost);
  cudaFree(d_c_as_float);

  double *c_as_double = new (c) double[cs.element_count<double>()];
  double* d_c_as_double;
  cudaMalloc(&d_c_as_double, size);
  cudaMemcpy(d_c_as_double, c_as_double, size, cudaMemcpyHostToDevice);
  double kernel_time_mad_dp = measure_operation([&] {
    bench_cuda<double, compute_iterations>(cs.element_count<double>(), d_c_as_double, nullptr);
  });
  cudaMemcpy(c_as_double, d_c_as_double, size, cudaMemcpyDeviceToHost);
  cudaFree(d_c_as_double);

  int *c_as_int = new (c) int[cs.element_count<int>()];
  int* d_c_as_int;
  cudaMalloc(&d_c_as_int, size);
  cudaMemcpy(d_c_as_int, c_as_int, size, cudaMemcpyHostToDevice);
  double kernel_time_mad_int = measure_operation([&] {
    bench_cuda<int, compute_iterations>(cs.element_count<int>(), d_c_as_int, nullptr);
  });
  cudaMemcpy(c_as_int, d_c_as_int, size, cudaMemcpyDeviceToHost);
  cudaFree(d_c_as_int);

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  std::cout << std::fixed << std::setw(9) << compute_iterations
            << ",   " << std::setw(8) << std::setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << std::setw(8) << std::setprecision(2) << kernel_time_mad_sp << ","
            << std::setw(8) << std::setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << std::setw(7) << std::setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << std::setw(8) << std::setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << std::setw(8) << std::setprecision(2) << kernel_time_mad_dp << ","
            << std::setw(8) << std::setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << std::setw(7) << std::setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << std::setw(8) << std::setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << std::setw(8) << std::setprecision(2) << kernel_time_mad_int << ","
            << std::setw(8) << std::setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << std::setw(7) << std::setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;
}

